#include<bits/stdc++.h>
using namespace std;
#define ll long long
ll n,m,ans[45];
struct xy{
	ll x,y;
	friend bool operator<(xy B,xy C){
		if(B.x==C.x)return B.y<C.y;
		return B.x<C.x;
	}
}a[45],g;
vector<xy>v2[25];
struct A{
	ll cnt,x,y;
};
vector<A>v1;
A k;
bool u;
void dfs(ll p){
	if(p==((u)?n:n/2))return;
	k.cnt++;k.x+=a[p+1].x;k.y+=a[p+1].y;
	(u)?v2[k.cnt].push_back({k.x,k.y}):v1.push_back(k);
	dfs(p+1);
	k.cnt--;k.x-=a[p+1].x;k.y-=a[p+1].y;
	dfs(p+1);
}
int main(){
	ios::sync_with_stdio(false);
	cin>>n>>g.x>>g.y;
	for(int i=1;i<=n;i++){
		cin>>a[i].x>>a[i].y;
	}
	v1.push_back(k);
	v2[0].push_back({0,0});
	u=0;
	dfs(0);
	u=1;
	dfs(n/2);
	for(int i=1;i<=20;i++){
		sort(v2[i].begin(),v2[i].end());
		//cout<<i<<' '<<v2[i].size()<<'\n';//
	}
	for(int i=0;i<v1.size();i++){
		xy tmp={g.x-v1[i].x,g.y-v1[i].y};
		for(int m=v1[i].cnt;m<=n;m++){
			ll k=m-v1[i].cnt;
			if(k>20)break;
			ll p1=lower_bound(v2[k].begin(),v2[k].end(),tmp)-v2[k].begin(),
			   p2=upper_bound(v2[k].begin(),v2[k].end(),tmp)-v2[k].begin();
			if(p1!=v2[k].size()&&p1!=p2)ans[m]+=p2-p1;
		}
	}
	for(int i=1;i<=n;i++)cout<<ans[i]<<'\n';
	return 0;
}
